package ratelimiter

import (
	"sync"
	"time"
)

// realClock implements Clock using the actual system time.
type realClock struct{}

func (rc *realClock) Now() time.Time { return time.Now() }

// bucket holds the token‑bucket state for a single key.
type bucket struct {
	lastRefill time.Time // last time the bucket was refilled
	tokens     float64   // current token count (may be fractional)
}

// limiter implements the Limiter interface.
type limiter struct {
	mu      sync.Mutex               // protects the buckets map
	cfg     Config                   // limiter configuration
	clock   Clock                    // time source (may be nil)
	buckets map[string]*bucket       // per‑key state
}

// newLimiter creates a Limiter based on the supplied configuration and clock.
// If clock is nil, the real system clock is used.
func newLimiter(cfg Config, clock Clock) Limiter {
	if clock == nil {
		clock = &realClock{}
	}
	// If Burst is zero, treat it as equal to Rate.
	if cfg.Burst == 0 {
		cfg.Burst = cfg.Rate
	}
	return &limiter{
		cfg:     cfg,
		clock:   clock,
		buckets: make(map[string]*bucket),
	}
}

// refill updates the token count for a bucket based on elapsed time.
func (l *limiter) refill(b *bucket, now time.Time) {
	elapsed := now.Sub(b.lastRefill).Seconds()
	if elapsed <= 0 {
		return
	}
	// Tokens are added at a constant rate: Rate per Window seconds.
	ratePerSec := float64(l.cfg.Rate) / l.cfg.Window.Seconds()
	b.tokens += elapsed * ratePerSec
	if max := float64(l.cfg.Burst); b.tokens > max {
		b.tokens = max
	}
	b.lastRefill = now
}

// Allow checks whether a request for the given key may proceed.
func (l *limiter) Allow(key string) bool {
	now := l.clock.Now()

	l.mu.Lock()
	defer l.mu.Unlock()

	// Retrieve or create the bucket for this key.
	b, ok := l.buckets[key]
	if !ok {
		// New buckets start full, allowing an initial burst.
		b = &bucket{
			lastRefill: now,
			tokens:     float64(l.cfg.Burst),
		}
		l.buckets[key] = b
	}

	// Refill tokens based on time passed since last refill.
	l.refill(b, now)

	// Consume a token if available.
	if b.tokens >= 1.0 {
		b.tokens -= 1.0
		return true
	}
	return false
}

// Reset clears the rate‑limiting state for the provided key.
func (l *limiter) Reset(key string) {
	l.mu.Lock()
	defer l.mu.Unlock()
	delete(l.buckets, key)
}
EOF
