type limiter struct {
	cfg     Config
	clock   Clock
	burst   int // effective burst size (>= Rate)
	mu      sync.Mutex
	buckets map[string]*tokenBucket
}

// getBucket retrieves (or creates) the bucket for a key.
func (l *limiter) getBucket(key string) *tokenBucket {
	l.mu.Lock()
	defer l.mu.Unlock()
	if b, ok := l.buckets[key]; ok {
		return b
	}
	b := &tokenBucket{
		last:   l.clock.Now(),
		tokens: float64(l.burst), // start full
	}
	l.buckets[key] = b
	return b
}

// Allow checks whether a request for the given key should be permitted.
func (l *limiter) Allow(key string) bool {
	b := l.getBucket(key)

	b.mu.Lock()
	defer b.mu.Unlock()

	now := l.clock.Now()
	elapsed := now.Sub(b.last)
	if elapsed < 0 {
		elapsed = 0
	}
	// tokens added per nanosecond
	ratePerNs := float64(l.cfg.Rate) / float64(l.cfg.Window)
	refill := float64(elapsed) * ratePerNs
	b.tokens += refill
	if b.tokens > float64(l.burst) {
		b.tokens = float64(l.burst)
	}
	b.last = now

	if b.tokens >= 1 {
		b.tokens -= 1
		return true
	}
	return false
}

// Reset clears rate limiting state for the given key.
func (l *limiter) Reset(key string) {
	l.mu.Lock()
	defer l.mu.Unlock()
	delete(l.buckets, key)
}
